const raw = $('ElevenLabs Webhook').first().json;
let input = raw;
if (raw?.body !== undefined && raw.body !== null) {
  if (typeof raw.body === 'string') {
    try { input = JSON.parse(raw.body); } catch { input = raw; }
  } else if (typeof raw.body === 'object' && !Array.isArray(raw.body)) {
    input = raw.body;
  }
}
const bool = (v) => v === true || v === 'true' || v === 1 || v === '1';
const num = (v, d = 0) => { const n = Number(v); return Number.isFinite(n) ? n : d; };

return [{
  json: {
    firstName: input.firstName || input.name || '',
    lastName: input.lastName || '',
    company: input.company || '',
    email: input.email || '',
    phone: input.phone || '',
    painPoint: input.painPoint || input.challenge || '',
    employeeCount: num(input.employeeCount ?? input.employees, 0),
    budgetMentioned: bool(input.budgetMentioned) || bool(input.hasBudget),
    decisionMaker: bool(input.decisionMaker) || bool(input.isDecisionMaker) || bool(input.descisionMaker),
    preferredDay: input.preferredDay || '',
    preferredTime: input.preferredTime || '',
    industry: input.industry || '',
    hasWebsite: bool(input.hasWebsite),
    rating: num(input.rating, 0),
    reviewCount: num(input.reviewCount, 0),
    hasPhoneFlag: bool(input.hasPhone)
  }
}];

const data = $('Extract Call Data').first().json;
const bool = (v) => v === true || v === 'true' || v === 1 || v === '1';
const num = (v, d = 0) => { const n = Number(v); return Number.isFinite(n) ? n : d; };

return [{
  json: {
    decisionMaker: bool(data.decisionMaker),
    budgetMentioned: bool(data.budgetMentioned),
    employeeCount: num(data.employeeCount, 0),
    painPoint: data.painPoint || '',
    reviewCount: num(data.reviewCount, 0),
    hasWebsite: bool(data.hasWebsite),
    rating: num(data.rating, 0),
    hasPhone: bool(data.hasPhoneFlag) || !!(data.phone && String(data.phone).trim())
  }
}];

